	<header class="topbar"><router-link class="brand" to="/music"><b-icon icon="music-circle" size="is-medium"/>{{ brandName }}</router-link><nav><router-link to="/music">音乐</router-link><router-link v-if="isAdmin" to="/admin">管理</router-link><button title="退出登录" @click="logout"><b-icon icon="logout"/></button></nav></header>
</template>
<script lang="ts">import Vue from "vue"; import { consoleApi, ConsoleUser } from "../ConsoleApi"; export default Vue.extend({data(){return {brandName:"波点音乐",isAdmin:false};},async created(){try{const u=await consoleApi<ConsoleUser>("me");this.brandName=u.brandName;this.isAdmin=u.role==="admin";}catch(_){this.$router.replace("/");}},methods:{async logout(){await consoleApi("logout",{});this.$router.replace("/");}}});</script>
